export function ImpactStatIcon({ name, size = 18 }: { name: 'miles' | 'locations' | 'sessions' | 'photos'; size?: number }) {
  switch (name) {
    case 'miles':
      return <MilesIcon size={size} />;
    case 'locations':
      return <LocationsIcon size={size} />;
    case 'sessions':
      return <SessionsCompletedIcon size={size} />;
    case 'photos':
      return <PhotosSubmittedIcon size={size} />;
    default: {
      const _exhaustive: never = name;
      return _exhaustive;
    }
  }
}
